import{_ as r,o as a,c as o,a3 as e}from"./chunks/framework.BTFg6ESq.js";const b=JSON.parse('{"title":"🎨 媒体生成中心：快速上手","description":"","frontmatter":{},"headers":[],"relativePath":"user-guide/tools/media-generator/index.md","filePath":"user-guide/tools/media-generator/index.md","lastUpdated":1778221347000}'),l={name:"user-guide/tools/media-generator/index.md"};function n(d,t,i,s,h,g){return a(),o("div",null,[...t[0]||(t[0]=[e('<h1 id="🎨-媒体生成中心-快速上手" tabindex="-1">🎨 媒体生成中心：快速上手 <a class="header-anchor" href="#🎨-媒体生成中心-快速上手" aria-label="Permalink to &quot;🎨 媒体生成中心：快速上手&quot;">​</a></h1><blockquote><p>一站式 AI 媒体生成工作站，支持图片、视频和音频的全流程创作。<br><strong>场景</strong>：用一句话描述画面，AI 帮你生成高清图片；让模型作曲编曲，生成一段独特旋律；创作短视频素材，快速出片。<br><strong>TODO：截图</strong></p></blockquote><hr><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p><strong>媒体生成中心</strong>（Media Generator）是一个基于 LLM 的媒体创作工具，允许你通过自然语言提示词直接生成图片、视频或音频内容。它采用<strong>会话式创作</strong>和<strong>快速单次生成</strong>两种工作模式，并深度集成了系统的资产管理体系——所有生成结果自动入库，随时回顾、下载或二次创作。</p><h3 id="核心能力" tabindex="-1">核心能力 <a class="header-anchor" href="#核心能力" aria-label="Permalink to &quot;核心能力&quot;">​</a></h3><table tabindex="0"><thead><tr><th>能力</th><th>说明</th></tr></thead><tbody><tr><td><strong>图片生成</strong></td><td>支持多种模型引擎，可配置分辨率、质量、风格、负向提示词等</td></tr><tr><td><strong>视频生成</strong></td><td>生成短视频素材，可配置分辨率和时长</td></tr><tr><td><strong>音频生成</strong></td><td>支持 Suno / 标准音频模型，可配置质量、风格标签等</td></tr><tr><td><strong>会话管理</strong></td><td>分支式会话树，支持多轮迭代和版本比较</td></tr><tr><td><strong>快速模式</strong></td><td>即开即用，不创建会话，适合快速试验</td></tr></tbody></table><hr><h2 id="进入工作台" tabindex="-1">进入工作台 <a class="header-anchor" href="#进入工作台" aria-label="Permalink to &quot;进入工作台&quot;">​</a></h2><p>在侧边栏点击 🎨 <strong>媒体生成中心</strong> 图标进入。主界面分为四个标签页：</p><table tabindex="0"><thead><tr><th>标签</th><th>用途</th></tr></thead><tbody><tr><td><strong>工作台</strong></td><td>核心创作区：左侧参数面板、中间生成流、右侧历史画廊</td></tr><tr><td><strong>画廊</strong></td><td>全屏浏览所有生成结果，支持搜索和筛选</td></tr><tr><td><strong>任务列表</strong></td><td>全局任务队列，查看进度、重试、下载</td></tr><tr><td><strong>生成设置</strong></td><td>精细配置：自动命名、提示词优化、翻译、并发等</td></tr></tbody></table><hr><h2 id="选择生成类型" tabindex="-1">选择生成类型 <a class="header-anchor" href="#选择生成类型" aria-label="Permalink to &quot;选择生成类型&quot;">​</a></h2><p>工作台左侧的 <strong>参数面板</strong> 顶部分为三种媒体类型：</p><ul><li>🖼️ <strong>图片</strong>（默认）—— 生成静态图像</li><li>🎬 <strong>视频</strong> —— 生成短视频</li><li>🎵 <strong>音频</strong> —— 生成音乐或音效</li></ul><p>点击相应按钮即可切换。<strong>每种类型的参数配置独立保存</strong>，切换时不会丢失已设置的参数。</p><hr><h2 id="配置生成参数" tabindex="-1">配置生成参数 <a class="header-anchor" href="#配置生成参数" aria-label="Permalink to &quot;配置生成参数&quot;">​</a></h2><h3 id="选择生成模型" tabindex="-1">选择生成模型 <a class="header-anchor" href="#选择生成模型" aria-label="Permalink to &quot;选择生成模型&quot;">​</a></h3><p>在参数面板的「生成模型」区域选择一个已配置好的 LLM 渠道和模型。系统会自动识别模型的能力（图片生成 / 视频生成 / 音频生成），并只显示匹配当前媒体类型的模型。</p><blockquote><p>模型支持的具体参数范围（如分辨率选项、质量等级、风格等）由 <strong>模型元数据系统</strong> 驱动。如果某些参数选项为空，请前往「设置 → 模型元数据」为对应模型补充能力描述。</p></blockquote><h3 id="图片参数详解" tabindex="-1">图片参数详解 <a class="header-anchor" href="#图片参数详解" aria-label="Permalink to &quot;图片参数详解&quot;">​</a></h3><table tabindex="0"><thead><tr><th>参数</th><th>说明</th></tr></thead><tbody><tr><td><strong>分辨率</strong></td><td>支持 <strong>预设</strong>、<strong>自定义宽高</strong>（64~4096px）或 <strong>宽高比模式</strong>（针对 xAI 等模型），支持一键交换宽高</td></tr><tr><td><strong>质量级别</strong></td><td>如标准 / HD，视模型支持情况而定</td></tr><tr><td><strong>生成风格</strong></td><td>如自然 / 艺术 / 写实等风格预设</td></tr><tr><td><strong>负向提示词</strong></td><td>描述你不希望在图片中出现的内容</td></tr><tr><td><strong>背景设置</strong></td><td>透明背景 / 纯色背景等</td></tr><tr><td><strong>输入保真度</strong></td><td>使用参考图时，控制对原始特征的保留程度</td></tr><tr><td><strong>流式预览图</strong></td><td>部分模型支持在生成过程中逐步显示预览图</td></tr><tr><td><strong>批量生成 (n)</strong></td><td>一次生成多张图片（1~4 张）</td></tr><tr><td><strong>内容审核 / 输出格式 / 输出压缩</strong></td><td>视模型支持情况</td></tr></tbody></table><h3 id="视频参数" tabindex="-1">视频参数 <a class="header-anchor" href="#视频参数" aria-label="Permalink to &quot;视频参数&quot;">​</a></h3><ul><li><strong>分辨率</strong>：1280x720（720p）或 1920x1080（1080p），也支持自定义</li><li><strong>时长</strong>：5 秒或 10 秒</li></ul><h3 id="音频参数" tabindex="-1">音频参数 <a class="header-anchor" href="#音频参数" aria-label="Permalink to &quot;音频参数&quot;">​</a></h3><ul><li><strong>Suno 模式</strong>：灵感模式（简单描述）或自定义模式（指定风格标签、标题、纯音乐等）</li><li><strong>非 Suno 模式</strong>：标准音质或高音质</li></ul><h3 id="高级参数" tabindex="-1">高级参数 <a class="header-anchor" href="#高级参数" aria-label="Permalink to &quot;高级参数&quot;">​</a></h3><p>点击「高级参数」折叠面板展开：</p><ul><li><strong>种子 (Seed)</strong>：-1 为随机，指定值可复现相同结果</li><li><strong>迭代步数 (Steps)</strong>：影响生成质量和速度</li><li><strong>引导系数 (CFG Scale)</strong>：提示词 adherence 程度</li></ul><hr><h2 id="两种创作模式" tabindex="-1">两种创作模式 <a class="header-anchor" href="#两种创作模式" aria-label="Permalink to &quot;两种创作模式&quot;">​</a></h2><h3 id="创作会话-默认" tabindex="-1">创作会话（默认） <a class="header-anchor" href="#创作会话-默认" aria-label="Permalink to &quot;创作会话（默认）&quot;">​</a></h3><p>适合多轮迭代和精细化创作：</p><ol><li>在输入框中输入提示词（支持 <code>Ctrl+Enter</code> 发送）</li><li>系统创建一条「用户」消息和一条「助手」生成任务</li><li>生成完成后，你可以： <ul><li><strong>重试</strong>：在消息上点击重试按钮，基于相同参数重新生成</li><li><strong>分支编辑</strong>：编辑用户消息创建新分支，在不同方向上迭代</li><li><strong>切换分支</strong>：通过分支选择器在不同结果间对比</li></ul></li><li>所有会话自动保存，支持创建新会话和历史切换</li></ol><blockquote><p><strong>提示</strong>：开启「连续对话」开关后，系统会将历史消息作为上下文发送给模型，支持迭代修改（如&quot;把上一张图改成冷色调&quot;）。此功能需要模型支持视觉输入。</p></blockquote><h3 id="快速生成" tabindex="-1">快速生成 <a class="header-anchor" href="#快速生成" aria-label="Permalink to &quot;快速生成&quot;">​</a></h3><p>适合快速试验：</p><ol><li>切换到「快速生成」模式</li><li>输入提示词，点击发送</li><li>任务执行后显示在任务队列中，不创建会话记录</li><li>支持「停止全部」和「清理已完成」操作</li></ol><hr><h2 id="使用参考图" tabindex="-1">使用参考图 <a class="header-anchor" href="#使用参考图" aria-label="Permalink to &quot;使用参考图&quot;">​</a></h2><p>如果你希望基于现有图片进行图生图或变体生成：</p><ol><li><strong>拖放</strong>：将图片文件拖入输入框区域</li><li><strong>粘贴</strong>：从剪贴板粘贴图片</li><li><strong>选择文件</strong>：点击输入框工具栏的附件按钮</li></ol><p>参考图会显示在输入框上方，可随时移除。</p><hr><h2 id="查看与管理生成结果" tabindex="-1">查看与管理生成结果 <a class="header-anchor" href="#查看与管理生成结果" aria-label="Permalink to &quot;查看与管理生成结果&quot;">​</a></h2><h3 id="工作台右侧面板" tabindex="-1">工作台右侧面板 <a class="header-anchor" href="#工作台右侧面板" aria-label="Permalink to &quot;工作台右侧面板&quot;">​</a></h3><p>点击右侧面板的「生成历史」，可按类型筛选（全部 / 图片 / 视频 / 音频），点击缩略图即可预览。</p><h3 id="画廊标签页" tabindex="-1">画廊标签页 <a class="header-anchor" href="#画廊标签页" aria-label="Permalink to &quot;画廊标签页&quot;">​</a></h3><p>切换到「画廊」标签页查看全量生成结果：</p><ul><li><strong>搜索</strong>：按提示词或模型名称搜索</li><li><strong>筛选</strong>：按媒体类型过滤</li><li><strong>预览</strong>：鼠标悬停可查看提示词，点击打开全屏查看器</li><li><strong>操作</strong>：查看生成参数、下载到本地、从画廊移除</li></ul><h3 id="任务列表标签页" tabindex="-1">任务列表标签页 <a class="header-anchor" href="#任务列表标签页" aria-label="Permalink to &quot;任务列表标签页&quot;">​</a></h3><p>切换到「任务列表」可查看全局任务队列：</p><ul><li>统计概览：总任务数、进行中、排队、完成、失败</li><li>筛选和搜索</li><li>每个任务卡片显示提示词、模型、进度或预览图</li><li>支持：复制提示词、取消任务、重新生成、下载、删除</li></ul><hr><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><ul><li>了解 <a href="./asset-management">生成结果的资产管理</a> —— 深入理解资产保存、批量管理和与资产管理器的集成</li><li>探索「生成设置」中的进阶选项，如自动命名、提示词优化、发送前翻译等</li></ul>',57)])])}const c=r(l,[["render",n]]);export{b as __pageData,c as default};
